int N = 5;
int sum = 0;
for (int i = 1; i <= N; i++) {
    sum += i;
}
System.out.println(sum);

java.util.Scanner scan = new java.util.Scanner(System.in);
int total = 0;
int count = 0;
while (true) {
    int x = scan.nextInt();
    if (x == -1) break;
    total += x;
    count++;
}
if (count > 0) {
    System.out.println((double) total / count);
} else {
    System.out.println("No data");
}

int n = 4;
for (int r = 1; r <= n; r++) {
    for (int c = 1; c <= n; c++) {
        int prod = r * c;
        System.out.printf("%4d", prod);
    }
    System.out.println();
}
